/**
 * Session pod type — one per Claude Code session.
 *
 * external_id  = Claude Code's `session_id` (from hook stdin envelope)
 * name         = autogenerated "claude-session YYYY-MM-DD HH:mm" for humans
 * entity_id    = null (session pods don't back an entity)
 * connection_id= null
 *
 * attrs shape (jsonb on the pod row):
 *   {
 *     "session_id":      "abc123-...",          // duplicate of external_id for convenience
 *     "transcript_path": "/Users/.../abc.jsonl",
 *     "cwd":             "/Users/.../my-repo",
 *     "turn_count":      0,
 *     "model":           "claude-opus-4-7",     // best-effort, may be null
 *     "conclusion":      null,                   // filled by SessionEnd
 *     "summary":         null
 *   }
 */

export const POD_TYPE = 'session';

export function buildAttrs({
  sessionId,
  transcriptPath = null,
  cwd = null,
  turnCount = 0,
  model = null,
  conclusion = null,
  summary = null,
}) {
  return {
    session_id: sessionId,
    transcript_path: transcriptPath,
    cwd,
    turn_count: turnCount,
    model,
    conclusion,
    summary,
  };
}

export function defaultName({ sessionId, startedAt = new Date() } = {}) {
  const d = startedAt instanceof Date ? startedAt : new Date(startedAt);
  const iso = d.toISOString().replace('T', ' ').slice(0, 16);
  const short = sessionId ? sessionId.slice(0, 8) : 'unknown';
  return `claude-session ${iso} (${short})`;
}

export function formatForDisplay(pod) {
  const a = parseAttrs(pod.attrs);
  return {
    uid: pod.uid,
    name: pod.name,
    sessionId: a.session_id ?? pod.externalId,
    transcriptPath: a.transcript_path,
    cwd: a.cwd,
    model: a.model,
    turnCount: a.turn_count ?? 0,
    conclusion: a.conclusion,
    startedAt: pod.startedAt,
    endedAt: pod.endedAt,
    memberFactCount: pod.memberFactCount,
    memberDocCount: pod.memberDocCount,
  };
}

function parseAttrs(attrs) {
  if (!attrs) return {};
  if (typeof attrs === 'object') return attrs;
  try { return JSON.parse(attrs); } catch { return {}; }
}
